#[test]
fn node_dot_string_rectangle_matches_java() {
    use svek::node::SvekNode;
    use svek::shape_type::ShapeType;

    // Java: shape=rect,label="",width=1.388889,height=0.694444,color="#010100"
    let mut n = SvekNode::new("sh0001", 100.0, 50.0);
    n.color = 0x010100;
    n.shape_type = ShapeType::Rectangle;
    let mut dot = String::new();
    n.append_shape(&mut dot);

    let expected =
        "\"sh0001\" [shape=rect,label=\"\",width=1.388889,height=0.694444,color=\"#010100\"];\n";
    assert_eq!(dot, expected, "rect DOT string mismatch");
}

