// ═══ 12. DOT output with full factory (end-to-end) ═════════════════

#[test]
fn dot_factory_simple_class_diagram() {
    use svek::edge::SvekEdge;
    use svek::node::SvekNode;
    use svek::shape_type::ShapeType;
    use svek::{Bibliotekon, DotMode, DotStringFactory};

    let mut bib = Bibliotekon::new();

    let mut n1 = SvekNode::new("Foo", 100.0, 50.0);
    n1.color = 0x010100;
    n1.shape_type = ShapeType::Rectangle;
    bib.add_node(n1);

    let mut n2 = SvekNode::new("Bar", 80.0, 40.0);
    n2.color = 0x020200;
    n2.shape_type = ShapeType::Rectangle;
    bib.add_node(n2);

    let mut e = SvekEdge::new("Foo", "Bar");
    e.color = 0x030300;
    bib.add_edge(e);

    let factory = DotStringFactory::new(bib);
    let dot = factory.create_dot_string(DotMode::Normal);

    // Verify structure (rankdir=TB is omitted as it is the default)
    assert!(dot.starts_with("digraph unix {\n"));
    assert!(dot.contains(
        "\"Foo\" [shape=rect,label=\"\",width=1.388889,height=0.694444,color=\"#010100\"];\n"
    ));
    assert!(dot.contains(
        "\"Bar\" [shape=rect,label=\"\",width=1.111111,height=0.555556,color=\"#020200\"];\n"
    ));
    assert!(dot.contains("\"Foo\"->\"Bar\""));
    assert!(dot.contains("color=\"#030300\""));
    assert!(dot.ends_with("}\n"));
}

#[test]
fn dot_factory_with_cluster() {
    use svek::cluster::Cluster;
    use svek::node::SvekNode;
    use svek::shape_type::ShapeType;
    use svek::{Bibliotekon, DotMode, DotStringFactory};

    let mut bib = Bibliotekon::new();

    let mut n = SvekNode::new("A", 100.0, 50.0);
    n.color = 0x010100;
    n.shape_type = ShapeType::Rectangle;
    bib.add_node(n);

    let mut c = Cluster::new("pkg");
    c.title = Some("MyPackage".to_string());
    c.add_node("A");
    bib.add_cluster(c);

    let factory = DotStringFactory::new(bib);
    let dot = factory.create_dot_string(DotMode::Normal);

    assert!(
        dot.contains("subgraph cluster_pkg {\n"),
        "cluster_pkg in: {}",
        dot
    );
    // Java uses HTML table label (cluster_dot_label), not plain string
    assert!(dot.contains("label=<"), "HTML table label in: {}", dot);
    // Node A should be inside cluster hierarchy
    let cluster_pos = dot.find("subgraph cluster_pkg").unwrap();
    let node_pos = dot.find("\"A\" [").unwrap();
    assert!(
        node_pos > cluster_pos,
        "Node A should appear after cluster_pkg opening"
    );
}

// ═══ 13. SVG header format (end-to-end) ═════════════════════════════

#[test]
fn class_diagram_svg_root_data_diagram_type() {
    // Java sets data-diagram-type="CLASS" for class diagrams
    // Verify our SVG root produces the same format
    use plantuml_little::klimt::svg::SvgGraphic;

    let mut svg = SvgGraphic::new(12345, 1.0);
    svg.set_max(79, 178);
    let doc = svg.to_svg(Some("#FFFFFF"), "CLASS");

    assert!(
        doc.contains("data-diagram-type=\"CLASS\""),
        "should have data-diagram-type=CLASS: {}",
        &doc[..200.min(doc.len())]
    );
    assert!(doc.contains("height=\"178px\""), "height=178px");
    assert!(doc.contains("width=\"79px\""), "width=79px");
    assert!(doc.contains("viewBox=\"0 0 79 178\""), "viewBox");
}

// ═══ 14. Margins ════════════════════════════════════════════════════

#[test]
fn margins_none_is_zero() {
    let m = svek::Margins::none();
    assert!(m.is_zero());
    assert_eq!(m.total_width(), 0.0);
    assert_eq!(m.total_height(), 0.0);
}

#[test]
fn margins_uniform() {
    let m = svek::Margins::uniform(5.0);
    assert!(!m.is_zero());
    assert_eq!(m.total_width(), 10.0);
    assert_eq!(m.total_height(), 10.0);
}

#[test]
fn margins_asymmetric() {
    let m = svek::Margins::new(10.0, 20.0, 5.0, 15.0);
    assert_eq!(m.total_width(), 30.0);
    assert_eq!(m.total_height(), 20.0);
}

